VALUES
  ('heelevel3-988e0de1-moex-00099', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '甲機關109年2月7日收到臺北自來水事業處繳費通知單，應繳總金額2萬元，並載明收費之計 費期間為108年12月1日至109年1月31日，繳付期限為109年2月14日，並於109年2月 10日繳付，則甲機關於何時認列支出？', '["於109年2月7日全數認列", "於109年2月10日全數認列", "於109年2月14日全數認列", "於108年底認列半數、於109年1月底認列半數"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "3858b88698af", "answer_pdf_sha1": "8a38ea7bc544", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1009", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00100', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '中央政府各機關辦理決算後，行政院與審計機關各依權責辦理查核修正支出，依中央政府普通公 務單位會計制度之一致規定，下列何項修正支出交易事項所作之會計分錄二者相同：', '["減列支出實現數改列應付數", "減列支出實現數改列歲出保留數", "減列應付數", "減列支出實現數改列賸餘繳庫數"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "3858b88698af", "answer_pdf_sha1": "8a38ea7bc544", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1009", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00101', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，Z 公司（甲機關 100%持有）配合政府民營化政 策，於X1年度將核心資產以作價入股方式，與民間合組Q公司繼續辦理原有營業項目。Z公司 作價投資之資產帳面價值1億元，取得新公司27%股權（270萬股，每股面額10元）及現金9,000 萬元。完成作價投資事宜後，Z 公司於 X3 年度完成辦理解散清算，已無負債，賸餘財產全數移 交甲機關。下列關於甲機關之敘述，何者錯誤？', '["應認列財產交易利益9,000萬元", "因本交易X1年底之「採權益法投資之評價調整」科目金額會有所增減", "應於Z公司完成解散清算時，認列投資損益", "應於接收Z公司財產後，對新公司之投資，仍應帳列「採權益法之投資」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "3858b88698af", "answer_pdf_sha1": "8a38ea7bc544", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1009", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00102', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '依中央總會計制度及中央政府普通公務單位會計制度之一致規定，甲機關為 A 作業基金及 B 特', '["對於A、B二基金之投資， 均帳列其他長期投資", "對於A作業基金於X3年度動用基金填補累計短絀，應借記採權益法之 投資評價調整及貸記採權益法之投資", "為編製中央總會計報告，甲機關須編造公務機關財務報 表，以及彙編A、B二基金的財務報表", "創設A、B二基金時，於會計處理時，均帳列採權益 法之投資"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "3858b88698af", "answer_pdf_sha1": "8a38ea7bc544", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1009", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00103', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '依政府會計準則公報規定，下列有關負債準備及或有負債之敘述何者正確？', '["政府因過去事件產生之現時法定義務，需要流出資源予以清償的可能性不高，應揭露或有負債", "政府因過去事件產生之可能法定義務，需要流出資源予以清償的可能性極小，應揭露或有負債", "政府因過去事件產生之現時法定義務，其很有可能需要流出資源予以清償，清償金額能可靠衡 量，應認列負債準備", "政府因過去事件產生之可能法定義務，清償金額能可靠衡量時，應認列負債準備"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "3858b88698af", "answer_pdf_sha1": "8a38ea7bc544", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1009", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00104', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '甲機關X9年1月1日預計撥入數科目餘額為$1,050,000，X9年5月核准動支第一預備金$100,000、 第二預備金$250,000及子女教育補助費$50,000，截至X9年6月底已分配之預算總額為$900,000， 請計算截至X9年6月底未分配預算總額為何？', '["$150,000", "$400,000", "$450,000", "$550,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "3858b88698af", "answer_pdf_sha1": "8a38ea7bc544", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1009", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00105', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '新冠肺炎（COVID-19）全球蔓延，甲機關X9年1月20日宣布啟動國際人道救援，將援贈友邦 各國醫療級口罩，預估金額介於$1,300,000至$1,800,000之間，最可能金額為$1,500,000，依政府 會計準則公報規定，甲機關X9年1月20日應認列之負債準備為何？', '["$0", "$1,300,000", "$1,500,000", "$1,800,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "3858b88698af", "answer_pdf_sha1": "8a38ea7bc544", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1009", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00106', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '有關中央總會計制度之敘述，下列何者錯誤？', '["公務機關之會計報告，包含普通公務單位會計之財務報表及特種公務會計應彙入總會計之財務 資訊", "中央總會計事務之範圍係將各級政府所屬公務機關及各特種基金之會計報告等資料彙編而為 綜合之報告", "採用之會計基礎為財務報表附註事項", "特種基金財務報表，係彙總特種基金之財務報表資訊，並分為營業部分及非營業部分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "3858b88698af", "answer_pdf_sha1": "8a38ea7bc544", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1009", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00107', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '甲機關公務車於107年10月1日撞壞民宅大門與圍牆，經參採維修廠商報價於年底估計須支付 民眾修復費用20萬元，嗣經調解於107年12月31日判定由該機關賠償民眾18萬元，依保險契 約規定保險公司同時確定可理賠16萬元，且於108年5月才會完成收付賠償給付及保險理賠， 則於107年底與本交易有關之未結帳帳載餘額何者正確？', '["其他獎補捐助20萬元", "其他收入16萬元", "罰款及賠償收入18萬元", "應付帳款18萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "3858b88698af", "answer_pdf_sha1": "8a38ea7bc544", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1009", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00108', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '審計機關查核甲機關年度單位決算時，發現其應收帳款餘額，部分係以前年度行政裁罰案件產生， 已超過行政程序法規定公法請求權時效，故應辦理註銷，依中央政府普通公務單位會計制度之一 致規定，審計機關辦理修正時應為之會計分錄為何？', '["借：罰款及賠償收入，貸：應收帳款", "借：公庫撥入數，貸：應收帳款", "借：繳付公庫數，貸：應收帳款", "借：資產負債淨額，貸：應收帳款"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "3858b88698af", "answer_pdf_sha1": "8a38ea7bc544", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1009", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL)
